// TracesPage is the constructor that builds the traces list page.
func TracesPage(ctx context.Context, store *collector.TraceStore, basePath string) (templ.Component, error) {
	if store == nil {
		return TracesPageContent(nil, collector.TraceStats{}, basePath), nil
	}

	traces, stats := store.ListTraces(collector.TraceFilter{Limit: 100})

	return TracesPageContent(traces, stats, basePath), nil
}

// statusFilterValue maps SpanStatus to the Alpine.js filter value.
func statusFilterValue(s collector.SpanStatus) string {
	switch s {
	case collector.SpanStatusOK:
		return "ok"
	case collector.SpanStatusError:
		return "error"
	default:
		return "unset"
	}
}

